package com.example.cms.data.backup; import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.stereotype.Service;import java.util.*; @Service public class BackupService{private final JdbcTemplate jdbc; public BackupService(JdbcTemplate jdbc){this.jdbc=jdbc;} public Map<String,Object> run(){jdbc.update("insert into backup_records(backup_type,status,target_scope,storage_location,performed_by,created_at) values ('MANUAL','SUCCESS','DATABASE_FILES','/backup/local','operator',now())"); return Map.of("status","SUCCESS","message","수동 백업 기록이 생성되었습니다.");} public List<Map<String,Object>> list(){return jdbc.queryForList("select * from backup_records order by created_at desc");}}
